const toHex = (value) => (value >>> 0).toString(16).padStart(8, '0');
const makeDeterministicUuid = (input) => {
  const text = String(input || 'unknown').toLowerCase().trim();
  let h1 = 2166136261;
  let h2 = 2166136261;
  let h3 = 2166136261;
  let h4 = 2166136261;

  for (let i = 0; i < text.length; i++) {
    const c = text.charCodeAt(i);
    h1 = Math.imul(h1 ^ c, 16777619) >>> 0;
    h2 = Math.imul(h2 ^ (c + 31), 16777619) >>> 0;
    h3 = Math.imul(h3 ^ (c + 131), 16777619) >>> 0;
    h4 = Math.imul(h4 ^ (c + 521), 16777619) >>> 0;
  }

  const hex = `${toHex(h1)}${toHex(h2)}${toHex(h3)}${toHex(h4)}`.slice(0, 32);
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
};

const results = $input.first().json.results || [];
return results.map((result) => {
  const creatorName = result.title || result.name || result.url;
  return {
    json: {
      creator_id: makeDeterministicUuid(creatorName),
      creator_name: creatorName,
      profile_url: result.url,
      source_query: 'AI automation creators',
      source_snippet: result.content || result.snippet || '',
      relevance_score: result.score || 0,
      platform: 'youtube'
    }
  };
});

const items = $input.all();
const apiKey = $env.YOUTUBE_API_KEY;
const results = [];

for (const item of items) {
  const url = String(item.json.profile_url || '');
  let channelId = null;
  let handle = null;

  const idMatch = url.match(/\/channel\/(UC[\w-]{10,})/i);
  if (idMatch) channelId = idMatch[1];

  if (!channelId) {
    const handleMatch = url.match(/\/@([\w.\-]+)/);
    if (handleMatch) handle = handleMatch[1];
  }

  if (!channelId && !handle) {
    const legacyMatch = url.match(/\/(?:c|user)\/([\w.\-]+)/i);
    if (legacyMatch) handle = legacyMatch[1];
  }

  let channelResponse;
  try {
    if (channelId) {
      channelResponse = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://www.googleapis.com/youtube/v3/channels',
        qs: { part: 'contentDetails,snippet', id: channelId, key: apiKey },
        json: true
      });
    } else if (handle) {
      channelResponse = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://www.googleapis.com/youtube/v3/channels',
        qs: { part: 'contentDetails,snippet', forHandle: handle, key: apiKey },
        json: true
      });
    } else {
      // Rare fallback for URL shapes we can't parse a handle/id out of -
      // this is the only branch that still pays the 100-unit search.list cost.
      const searchResponse = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://www.googleapis.com/youtube/v3/search',
        qs: { part: 'snippet', type: 'channel', maxResults: 1, q: item.json.creator_name, key: apiKey },
        json: true
      });
      channelId = searchResponse.items?.[0]?.snippet?.channelId || searchResponse.items?.[0]?.id?.channelId || null;
      if (channelId) {
        channelResponse = await this.helpers.httpRequest({
          method: 'GET',
          url: 'https://www.googleapis.com/youtube/v3/channels',
          qs: { part: 'contentDetails,snippet', id: channelId, key: apiKey },
          json: true
        });
      }
    }
  } catch (error) {
    results.push({ json: { ...item.json, items: [], resolution_error: String(error) } });
    continue;
  }

  const channel = channelResponse?.items?.[0];
  const uploadsPlaylistId = channel?.contentDetails?.relatedPlaylists?.uploads;
  const resolvedChannelId = channel?.id || channelId;

  if (!uploadsPlaylistId) {
    results.push({ json: { ...item.json, items: [], resolved_channel_id: resolvedChannelId, resolution_error: 'no_uploads_playlist' } });
    continue;
  }

  let videoIds = [];
  try {
    const playlistResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.googleapis.com/youtube/v3/playlistItems',
      qs: { part: 'contentDetails', playlistId: uploadsPlaylistId, maxResults: 10, key: apiKey },
      json: true
    });
    videoIds = (playlistResponse.items || []).map((p) => p.contentDetails?.videoId).filter(Boolean);
  } catch (error) {
    results.push({ json: { ...item.json, items: [], resolved_channel_id: resolvedChannelId, resolution_error: String(error) } });
    continue;
  }

  let videos = [];
  if (videoIds.length) {
    try {
      const videosResponse = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://www.googleapis.com/youtube/v3/videos',
        qs: { part: 'snippet,statistics,contentDetails', id: videoIds.join(','), key: apiKey },
        json: true
      });
      videos = videosResponse.items || [];
    } catch (error) {
      results.push({ json: { ...item.json, items: [], resolved_channel_id: resolvedChannelId, resolution_error: String(error) } });
      continue;
    }
  }

  results.push({
    json: {
      ...item.json,
      resolved_channel_id: resolvedChannelId,
      uploads_playlist_id: uploadsPlaylistId,
      items: videos
    }
  });
}

return results;

const parseIsoDuration = (iso) => {
  const match = /^PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?$/.exec(iso || '');
  if (!match) return null;
  const [, h, m, s] = match;
  return (Number(h || 0) * 3600) + (Number(m || 0) * 60) + Number(s || 0);
};

const toHex = (value) => (value >>> 0).toString(16).padStart(8, '0');
const makeDeterministicUuid = (input) => {
  const text = String(input || 'unknown').toLowerCase().trim();
  let h1 = 2166136261;
  let h2 = 2166136261;
  let h3 = 2166136261;
  let h4 = 2166136261;

  for (let i = 0; i < text.length; i++) {
    const c = text.charCodeAt(i);
    h1 = Math.imul(h1 ^ c, 16777619) >>> 0;
    h2 = Math.imul(h2 ^ (c + 31), 16777619) >>> 0;
    h3 = Math.imul(h3 ^ (c + 131), 16777619) >>> 0;
    h4 = Math.imul(h4 ^ (c + 521), 16777619) >>> 0;
  }

  const hex = `${toHex(h1)}${toHex(h2)}${toHex(h3)}${toHex(h4)}`.slice(0, 32);
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
};

const creators = $input.all();
return creators.flatMap((item) => {
  const videos = item.json.items || [];
  return videos.map((video) => {
    const viewCount = Number(video.statistics?.viewCount || 0);
    const likeCount = Number(video.statistics?.likeCount || 0);
    const commentCount = Number(video.statistics?.commentCount || 0);
    const engagementRate = viewCount > 0 ? Number(((likeCount + commentCount) / viewCount).toFixed(4)) : 0;
    const creatorName = item.json.creator_name || video.snippet?.channelTitle || String(video.snippet?.channelId || 'unknown_creator');

    return {
      json: {
        creator_id: item.json.creator_id || makeDeterministicUuid(creatorName),
        creator_name: creatorName,
        profile_url: item.json.profile_url,
        platform_video_id: video.id?.videoId || video.id,
        title: video.snippet?.title || '',
        description: video.snippet?.description || '',
        published_at: video.snippet?.publishedAt || null,
        duration_seconds: parseIsoDuration(video.contentDetails?.duration),
        view_count: viewCount,
        like_count: likeCount,
        comment_count: commentCount,
        engagement_rate: engagementRate,
        thumbnail_url: video.snippet?.thumbnails?.high?.url || video.snippet?.thumbnails?.default?.url || null,
        raw_payload: video,
        hashtags: [],
        format_tags: []
      }
    };
  });
});

const records = $input.all();
const batchId = $env.STAGE3_BATCH_ID || `batch-${new Date().toISOString().replace(/[:.]/g, '-')}`;
return records.map((item) => ({
  json: {
    ...item.json,
    batch_id: batchId,
    analysis_version: 'stage3-v1',
    analysis_status: 'pending',
    analysis_payload: {
      analysis_version: 'stage3-v1',
      batch_id: batchId,
      creator_name: item.json.creator_name,
      platform: 'youtube',
      platform_video_id: item.json.platform_video_id,
      title: item.json.title,
      description: item.json.description,
      published_at: item.json.published_at,
      duration_seconds: item.json.duration_seconds,
      view_count: item.json.view_count,
      like_count: item.json.like_count,
      comment_count: item.json.comment_count,
      hashtags: item.json.hashtags || [],
      engagement_rate: item.json.engagement_rate,
      format_tags: item.json.format_tags || []
    },
    topic_category: null,
    primary_format: null,
    engagement_tier: null,
    analysis_confidence: null,
    pattern_summary: {}
  }
}));

