const source = $input.first().json || {};
return [{
  json: {
    ...source,
    playbook_status: 'skipped_not_analyzed',
    playbook_page_id: null,
    playbook_synced_at: null,
    playbook_payload: {
      ...(source.playbook_payload || {}),
      skip_reason: `analysis_status_${source.analysis_status || 'unknown'}`
    }
  }
}];

const source = $('Stage 4 Playbook Mapper').first().json || {};
const response = $input.first().json || {};
return [{
  json: {
    ...source,
    playbook_status: 'synced',
    playbook_page_id: response.id || null,
    playbook_synced_at: new Date().toISOString(),
    playbook_payload: {
      ...(source.playbook_payload || {}),
      notion_response_id: response.id || null,
      notion_url: response.url || null
    }
  }
}];

const source = $input.first().json || {};
const eligible = source.analysis_status === 'analyzed' && source.playbook_status === 'synced';
const score = eligible && typeof source.analysis_confidence === 'number'
  ? Number(source.analysis_confidence.toFixed(4))
  : null;

return [{
  json: {
    ...source,
    feedback_status: 'pending_first_party_data',
    feedback_score: score,
    feedback_payload: {
      batch_id: source.batch_id || null,
      platform_video_id: source.platform_video_id || null,
      stage4_status: source.playbook_status || 'unknown',
      analysis_status: source.analysis_status || 'unknown',
      scaffold_mode: 'deferred_until_first_party_metrics',
      eligible_for_blend: Boolean(eligible),
      next_action: 'ingest_first_party_posts'
    }
  }
}];

const items = $input.all();
const first = items[0]?.json || {};
return [{
  json: {
    batch_id: first.batch_id || null,
    status: 'ingested',
    provider: $env.STAGE3_MODEL_PROVIDER || 'claude',
    run_finished_at: new Date().toISOString(),
    video_count: items.length
  }
}];
